  prop TEXT;
  pval JSONB;
BEGIN
  -- value known to be an object
  FOR prop, pval IN SELECT * FROM JSONB_EACH(val) LOOP
    IF _jm_re_0(prop, NULL, NULL) THEN
      -- handle 1 re props
      -- .'&'.1.'/^d[0-9]/'
